// components/ProductCard.jsx
import { Link } from 'react-router-dom';

const ProductCard = ({ product }) => {
  // Handle missing or broken images
  const placeholderImage = 'https://via.placeholder.com/400x500/1a1a2e/ffffff?text=No+Image';

  // Check if product has image property
  const imageUrl = product.image || product.images?.[0] || product.imageUrl || product.thumbnail;

  // An image is "already complete" if it's a full http(s) URL or a base64
  // data URI (locally-uploaded photos are stored this way). Only relative
  // paths (e.g. "/uploads/xyz.jpg") need the API URL prefixed.
  const isCompleteUrl = (url) => url.startsWith('http') || url.startsWith('data:');

  const fullImageUrl = imageUrl
    ? (isCompleteUrl(imageUrl) ? imageUrl : `${process.env.REACT_APP_API_URL || ''}${imageUrl}`)
    : placeholderImage;

  return (
    <div className="product-card" style={{
      backgroundColor: '#ffffff',
      borderRadius: '12px',
      overflow: 'hidden',
      transition: 'all 0.3s ease',
      boxShadow: '0 2px 15px rgba(0,0,0,0.08)',
      display: 'flex',
      flexDirection: 'column'
    }}>
      <Link to={`/products/${product._id}`} style={{ textDecoration: 'none', color: 'inherit' }}>
        <div style={{
          width: '100%',
          height: '300px',
          overflow: 'hidden',
          backgroundColor: '#f8f9fa',
          position: 'relative'
        }}>
          <img 
            src={fullImageUrl} 
            alt={product.name || product.title || 'Product'}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              transition: 'transform 0.3s ease'
            }}
            loading="lazy"
            onError={(e) => {
              e.target.onerror = null; // Prevent infinite loop
              e.target.src = placeholderImage;
            }}
          />
          {product.isFeatured && (
            <div style={{
              position: 'absolute',
              top: '15px',
              right: '15px',
              backgroundColor: '#e94560',
              color: '#ffffff',
              padding: '5px 15px',
              borderRadius: '20px',
              fontSize: '0.8rem',
              fontWeight: '700'
            }}>
              Featured
            </div>
          )}
        </div>

        <div style={{ padding: '20px', flex: 1, display: 'flex', flexDirection: 'column' }}>
          <h3 style={{
            fontSize: '1.1rem',
            fontWeight: '600',
            color: '#1a1a2e',
            marginBottom: '10px',
            lineHeight: '1.4'
          }}>
            {product.name || product.title || 'Unnamed Product'}
          </h3>

          {product.category && (
            <p style={{
              color: '#666',
              fontSize: '0.9rem',
              marginBottom: '10px'
            }}>
              {product.category}
            </p>
          )}

          <div style={{ marginTop: 'auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{
              fontSize: '1.3rem',
              fontWeight: '700',
              color: '#e94560'
            }}>
              PKR.{product.price?.toFixed(2) || '0.00'}
            </span>

            {product.rating && (
              <span style={{
                color: '#f59e0b',
                fontSize: '0.9rem'
              }}>
                ★ {product.rating.toFixed(1)}
              </span>
            )}
          </div>
        </div>
      </Link>
    </div>
  );
};

export default ProductCard;
